/// Convert a `kreuzberg::error::KreuzbergError` error to a `JsValue` string.
#[allow(dead_code)]
fn kreuzberg_error_to_js_value(e: kreuzberg::error::KreuzbergError) -> wasm_bindgen::JsValue {
    wasm_bindgen::JsValue::from_str(&e.to_string())
}
